void to_c(const pyramid::domain_model::agra::VideoOutputSettingsType& in, pyramid_data_model_agra_VideoOutputSettingsType_c* out) {
  std::memset(out, 0, sizeof(*out));
  out->enable = in.enable ? 1u : 0u;
  {
    const auto count = in.source_channel.size();
    if (count > 0) {
      auto* arr = static_cast<uint32_t*>(pcl_alloc(count * sizeof(uint32_t)));
      for (size_t i = 0; i < count; ++i) {
        arr[i] = in.source_channel[i];
      }
      out->source_channel.ptr = arr;
      out->source_channel.len = static_cast<uint32_t>(count);
    }
  }
  {
    const auto count = in.output.size();
    if (count > 0) {
      auto* arr = static_cast<pyramid_data_model_agra_VideoEncoderOutputType_c*>(pcl_alloc(count * sizeof(pyramid_data_model_agra_VideoEncoderOutputType_c)));
      for (size_t i = 0; i < count; ++i) {
        to_c(in.output[i], &arr[i]);
      }
      out->output.ptr = arr;
      out->output.len = static_cast<uint32_t>(count);
    }
  }
  to_c(in.encoder_settings, &out->encoder_settings);
}

void from_c(const pyramid_data_model_agra_VideoOutputSettingsType_c* in, pyramid::domain_model::agra::VideoOutputSettingsType& out) {
  out.enable = in->enable != 0;
  out.source_channel.clear();
  if (in->source_channel.ptr && in->source_channel.len > 0) {
    const auto* arr = static_cast<const uint32_t*>(in->source_channel.ptr);
    out.source_channel.reserve(in->source_channel.len);
    for (uint32_t i = 0; i < in->source_channel.len; ++i) {
      out.source_channel.push_back(arr[i]);
    }
  }
  out.output.clear();
  if (in->output.ptr && in->output.len > 0) {
    const auto* arr = static_cast<const pyramid_data_model_agra_VideoEncoderOutputType_c*>(in->output.ptr);
    out.output.reserve(in->output.len);
    for (uint32_t i = 0; i < in->output.len; ++i) {
      pyramid::domain_model::agra::VideoEncoderOutputType elem{};
      from_c(&arr[i], elem);
      out.output.push_back(std::move(elem));
    }
  }
  from_c(&in->encoder_settings, out.encoder_settings);
}

void _free_VideoOutputSettingsType(pyramid_data_model_agra_VideoOutputSettingsType_c* value) {
  if (!value) {
    return;
  }
  if (value->source_channel.ptr) {
    pcl_free(const_cast<void*>(value->source_channel.ptr));
    value->source_channel.ptr = nullptr;
    value->source_channel.len = 0;
  }
  if (value->output.ptr) {
    auto* arr = static_cast<pyramid_data_model_agra_VideoEncoderOutputType_c*>(const_cast<void*>(value->output.ptr));
    for (uint32_t i = 0; i < value->output.len; ++i) {
      pyramid_data_model_agra_VideoEncoderOutputType_c_free(&arr[i]);
    }
    pcl_free(const_cast<void*>(value->output.ptr));
    value->output.ptr = nullptr;
    value->output.len = 0;
  }
  pyramid_data_model_agra_VideoEncoderSettingsType_c_free(&value->encoder_settings);
}

